class SakanaWidget {
  static mount({ el, character }) {
    const container = document.querySelector(el);
    if (!container) {
      throw new Error("Invalid mounting element");
    }

    const img = document.createElement("img");
    img.src =
      character === "chisato"
        ? "https://i.imgur.com/6X4Z4qX.png"
        : "";

    img.style.width = "120px";
    img.style.cursor = "grab";
    img.draggable = false;

    let angle = 0;
    let velocity = 0;
    let dragging = false;
    let lastX = 0;

    img.addEventListener("mousedown", (e) => {
      dragging = true;
      lastX = e.clientX;
    });

    window.addEventListener("mouseup", () => {
      dragging = false;
    });

    window.addEventListener("mousemove", (e) => {
      if (!dragging) return;
      let dx = e.clientX - lastX;
      lastX = e.clientX;

      angle += dx * 0.01;
      velocity = dx * 0.02;
    });

    function animate() {
      if (!dragging) {
        velocity *= 0.95;
        angle += velocity;
      }

      img.style.transform = `rotate(${angle}rad)`;
      requestAnimationFrame(animate);
    }

    animate();

    container.appendChild(img);
  }
}
